Code:
public String alarmClock(int day, boolean vacation) {
    if (vacation) {
        // On vacation
        if (day == 0 || day == 6) {
            return "off";  // Weekend
        } else {
            return "10:00";  // Weekday
        }
    } else {
        // Not on vacation
        if (day == 0 || day == 6) {
            return "10:00";  // Weekend
        } else {
            return "7:00";  // Weekday
        }
    }
}
